mapper.select:
select fd.id, case when exists (
select DISTINCT dept_name from fnd_dept where enabled_flag = 1 and deleted_flag = 0 and dept_name = fd.dept_name GROUP BY dept_name having count(1) > 1 ) then (select dept_name from fnd_dept where enabled_flag = 1 and deleted_flag = 0 and id = fd.parent_id) + '.' + fd.dept_name else fd.dept_name end as dept_name, fd.parent_id, fd.enabled_flag, fd.dept_code, fd.dept_level, fd.dept_sequence, fd.deleted_flag, fd.create_time, fd.create_by, fd.update_time, fd.update_by, fd.ext_dept_id, fd.ext_department_id, fd.ext_team_id, fd.admin_job_id , (select dept_name from fnd_dept fdcopy1 where fdcopy1.id = fd.ext_dept_id) ext_dept_name , (select dept_name from fnd_dept fdcopy2 where fdcopy2.id = fd.ext_department_id) ext_department_name , (select dept_name from fnd_dept fdcopy3 where fdcopy3.id = fd.ext_team_id) ext_team_name from fnd_dept fd
where exists (select 1 from fnd_dept fdt WHERE fdt.id = fd.id and fdt.id in
#{item, jdbcType=BIGINT}
) order by fd.id


		    select fd.dept_name
              from fnd_dept fd
             where fd.id = #{id,jdbcType=BIGINT}

mapper.update:

update fnd_dept
   set deleted_flag = #{deletedFlag,jdbcType=BIT},
       update_time  = #{updateTime,jdbcType=TIMESTAMP},
       update_by    = #{updateBy,jdbcType=BIGINT}
 where id = #{id,jdbcType=BIGINT}


update fnd_dept
   set dept_sequence = #{deptSequence,jdbcType=INTEGER},
       update_time   = #{updateTime,jdbcType=TIMESTAMP},
       update_by     = #{updateBy,jdbcType=BIGINT}
 where id = #{id,jdbcType=BIGINT}

mapper.select:
select isnull(education, '无') as name ,count(isnull(education, '无')) as value from (select pe.id as id from pm_employee pe, pm_employee_job pej where pe.leave_flag = 0 and pe.enabled_flag = 1 and pej.enabled_flag = 1 and pej.job_main_flag = 1 and pej.employee_id = pe.id and pej.dept_id in
#{item, jdbcType = BIGINT}
) temp left join pm_employee_education pee on temp.id = pee.employee_id and pee.new_education_flag = 1 and pee.enabled_flag = 1 GROUP BY education

select ISNULL(pe.company_age, 0) from pm_employee pe,pm_employee_job pej where pe.leave_flag = 0 and pe.enabled_flag = 1 and pej.enabled_flag = 1 and pej.job_main_flag = 1 and pej.employee_id = pe.id and pej.dept_id in
#{item, jdbcType = BIGINT}
order by 1

select isnull(vocational_level, '无') as name ,count(isnull(vocational_level, '无')) as value from (select pe.id as id from pm_employee pe, pm_employee_job pej where pe.leave_flag = 0 and pe.enabled_flag = 1 and pej.enabled_flag = 1 and pej.job_main_flag = 1
and pej.employee_id = pe.id and pej.dept_id in
#{item, jdbcType = BIGINT}
) temp left join
pm_employee_vocational pev on temp.id = pev.employee_id and pev.enabled_flag = 1 and pev.new_vocational_flag = 1 GROUP BY vocational_level

mapper.update:

update fnd_dept
set dept_sequence = dept_sequence + 1
where deleted_flag = 0
  and dept_sequence >= #{sequence,jdbcType=BIGINT}
  and parent_id = #{pId,jdbcType=BIGINT}


update fnd_dept
set dept_sequence = dept_sequence + 1
where deleted_flag = 0
  and dept_sequence >= #{minSequence,jdbcType=BIGINT}
  and dept_sequence < #{maxSequence,jdbcType=BIGINT}
  and parent_id = #{pId,jdbcType=BIGINT}


update fnd_dept
set dept_sequence = dept_sequence - 1
where deleted_flag = 0
  and dept_sequence > #{minSequence,jdbcType=BIGINT}
  and dept_sequence <= #{maxSequence,jdbcType=BIGINT}
  and parent_id = #{pId,jdbcType=BIGINT}


update fnd_dept
set dept_sequence = dept_sequence - 1
where deleted_flag = 0
  and dept_sequence > #{sequence,jdbcType=BIGINT}
  and parent_id = #{pId,jdbcType=BIGINT}

mapper.select:
with dept_admin_t as( select pejv.job_id,
from pm_employee_job pejv join pm_employee pe on pejv.employee_id = pe.id and pe.enabled_flag = 1 and pe.leave_flag = 0 where pejv.enabled_flag = 1) select
, dept_admin_t.* from fnd_dept fd join pm_employee_job pej on fd.id = pej.dept_id and pej.enabled_flag = 1 and pej.job_main_flag = 1 left join dept_admin_t on fd.admin_job_id = dept_admin_t.job_id where fd.enabled_flag = 1 and fd.deleted_flag = 0 and pej.employee_id = #{employeeId,jdbcType = BIGINT}

select
,
from fnd_dept fd left join pm_employee_job pej on fd.id = pej.dept_id and pej.enabled_flag = 1 and pej.job_main_flag = 1 and fd.admin_job_id = pej.job_id left join pm_employee pe on pej.employee_id = pe.id and pe.enabled_flag = 1 and pe.leave_flag = 0 where fd.enabled_flag = 1 and fd.deleted_flag = 0 and fd.id = #{deptId,jdbcType = BIGINT}
